def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                temp = np.cos(ratio * a * np.pi) * (a ** 2.7)
                if a % 4 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.1
                score += temp
            if (int(capacity + item) % 4 == 0) or (int(capacity - item) % 6 == 0):
                score *= 0.75
            if score > 12:
                score /= 3.2
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity**0.5) + 3):
                val = ratio + (n / (n + 2))**1.5
                prod *= val if val != 0 else 1
                if prod > 2e6:
                    prod = np.log1p(prod) ** 2
                    break
            mod_val = int(prod*7) % 350
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 7) % 4 == 1):
                score += 5.7
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                frac_part = ((ratio * (x**3)) % 1)
                extra_sum += frac_part * (x ** 2.2)
            score += extra_sum / 6
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                inc = (ratio ** (m + 3)) * (m ** 3) / ((m + 2) ** 1.1)
                score += inc
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 18:
                score /= 4
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 12):
                pen_term = ((ratio - 0.5) ** p) * (p ** 1.8)
                penalty_base += pen_term
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.2
                    break
            score = penalty_base * 10
            if capacity < item * 1.07:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 10) % 13 == 0):
                score -= 7
            if score < 0:
                score *= -1.8
                score += 8
            if score > 150:
                score = 150
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.7)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 2) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.3)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1800:
                score = 1800
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 11) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) * 0.85 + 1.5)
        elif capacity < 7:
            score *= 3.1
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        median_val = q2
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.3
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
